import{o as t,f as r,y as n}from"./framework.2171159c.js";const o='{"title":"Панчакшара мантра","description":"","frontmatter":{"title":"Панчакшара мантра","subtitle":"पञ्चक्षरमन्त्र - pañcakṣaramantra - Пятислоговая мантра","tags":"mantra"},"relativePath":"mantra/panchakshara/index.md","lastUpdated":1624822425171}',s={},a=n("<p>ॐ नमः शिवाय om namah śivāya Поклонение Благому</p><p>Основные толкования:</p><ul><li><strong>Толкование джняни</strong>. Слово «<strong>намах</strong>» (नमः) обозначает ограниченную человеческую душу (дживу, जिव). Слово «<strong>шива</strong>» (शिव) обозначает Мировой Дух (Параматман). Окончание «<strong>йа</strong>» (य) указывает на идентичность Дживы и Параматмана. Слог <strong>Ом</strong> (ॐ) символизирует разрушение <strong>Майи</strong> — иллюзии.</li><li><strong>Толкование бхакти</strong>. Слог «<strong>ом</strong>» (ॐ) означает «весь мир, живой и неживой». Слово «намах» (नमः) — это сокращение от «<strong>намама</strong>» (न मम) — «не мой», «не для меня». Слово «<strong>шивайа</strong>» (शिवाय) означает «для Шивы». Мантра в целом переводится так: весь этот мир, живой и неживой, принадлежит не мне, существует не для меня, а для Шивы.</li></ul><p>Хотя она и имеет прямой перевод — <strong>Поклонение Благому</strong>, — её основное значение заключается не в словах, а в звуках, её составляющих, которые, в свою очередь, связываются с пятью перво-элементами (землёй, водой, огнём, воздухом и акашей) и ипостасью Шивы — <strong>Панчамукха</strong> или <strong>Панчанана</strong> ([Обладающий] Пятью ликами).</p>",4);s.render=function(n,o,s,g,e,i){return t(),r("div",null,[a])};export default s;export{o as __pageData};
